@system_bp.route('/logs', methods=['GET'])
@login_required
@require_role('admin')
def list_logs():
    """操作日志（分页）"""
    page = request.args.get('page', 1, type=int)
    page_size = request.args.get('page_size', 20, type=int)
    module = request.args.get('module', '')
    action = request.args.get('action', '')
    date_start = request.args.get('date_start', '')
    date_end = request.args.get('date_end', '')
    user_id = request.args.get('user_id', type=int)

    query = OperationLog.query

    if module:
        query = query.filter(OperationLog.module == module)
    if action:
        query = query.filter(OperationLog.action == action)
    if date_start:
        query = query.filter(func.date(OperationLog.created_at) >= date_start)
    if date_end:
        query = query.filter(func.date(OperationLog.created_at) <= date_end)
    if user_id:
        query = query.filter(OperationLog.user_id == user_id)

    query = query.order_by(OperationLog.created_at.desc())

    result = paginate(query, page=page, page_size=page_size)

    data = []
    for l in result['list']:
        data.append({
            'id': l.id,
            'user_id': l.user_id,
            'username': l.username,
            'module': l.module,
            'action': l.action,
            'content': l.content,
            'ip_address': l.ip_address,
            'duration': l.duration,
            'created_at': l.created_at.strftime('%Y-%m-%d %H:%M:%S') if l.created_at else None,
        })

    return success_response({
        'list': data,
        'total': result['total'],
        'page': result['page'],
        'page_size': result['page_size'],
    })


