@system_bp.route('/backup', methods=['GET'])
@login_required
@require_role('admin')
def backup():
    """数据库备份（返回SQL文件）"""
    import subprocess
    import tempfile
    import os
    from datetime import datetime as dt

    db_url = Config.SQLALCHEMY_DATABASE_URI

    # Parse mysql+pymysql://user:password@host:port/dbname
    # Format: mysql+pymysql://root:@127.0.0.1:3306/arms_db
    try:
        url_part = db_url.replace('mysql+pymysql://', '')
        creds_host, db_name = url_part.rsplit('/', 1)
        if ':' in creds_host.rsplit('@', 1)[0] if '@' in creds_host else True:
            # user:password@host:port
            user_pass, host_port = creds_host.split('@')
            if ':' in user_pass:
                user, password = user_pass.split(':', 1)
            else:
                user, password = user_pass, ''
            if ':' in host_port:
                host, port = host_port.split(':')
            else:
                host, port = host_port, '3306'
    except Exception:
        return error_response('无法解析数据库连接字符串', 500)

    tmp_file = tempfile.NamedTemporaryFile(suffix='.sql', delete=False)
    tmp_file.close()

    try:
        cmd = ['mysqldump', '-h', host, '-P', port, '-u', user]
        if password:
            cmd.extend(['-p' + password])
        cmd.append(db_name)

        with open(tmp_file.name, 'w') as f:
            result = subprocess.run(cmd, stdout=f, stderr=subprocess.PIPE, text=True)
            if result.returncode != 0:
                return error_response(f'备份失败: {result.stderr}', 500)

        log_operation(
            user_id=g.get('current_user_id'),
            username=g.get('current_username', ''),
            module='系统管理',
            action='数据库备份',
            content='数据库备份',
        )

        return send_file(
            tmp_file.name,
            mimetype='application/sql',
            as_attachment=True,
            download_name=f'backup_{dt.now().strftime("%Y%m%d_%H%M%S")}.sql',
        )
    except Exception as e:
        return error_response(f'备份失败: {str(e)}', 500)
    finally:
        try:
            os.unlink(tmp_file.name)
        except OSError:
            pass

"""文件上传路由"""

import os
import uuid
from datetime import datetime
from flask import Blueprint, g, request, send_file, current_app
from werkzeug.utils import secure_filename

from app.utils.auth import login_required
from app.utils.helpers import success_response, error_response

upload_bp = Blueprint('upload', __name__, url_prefix='/api/upload')

ALLOWED_EXTENSIONS = {'pdf', 'doc', 'docx', 'xls', 'xlsx', 'jpg', 'jpeg', 'png'}


def allowed_file(filename):
    """Check if the file extension is allowed."""
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


@upload_bp.route('/', methods=['POST'])
@login_required
def upload_files():
    """上传文件（支持多文件）"""
    if 'files' not in request.files:
        return error_response('请选择要上传的文件')

    files = request.files.getlist('files')
    if not files or len(files) == 0:
        return error_response('请选择要上传的文件')

    upload_dir = current_app.config.get('UPLOAD_FOLDER', 'uploads')
    os.makedirs(upload_dir, exist_ok=True)

    uploaded = []
    for file in files:
        if file.filename == '':
            continue

        if not allowed_file(file.filename):
            return error_response(f'不支持的文件类型: {file.filename}')

        ext = file.filename.rsplit('.', 1)[1].lower()
        new_filename = f"{datetime.now().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex[:8]}.{ext}"
        filepath = os.path.join(upload_dir, new_filename)
        file.save(filepath)

        uploaded.append({
            'original_name': file.filename,
            'filename': new_filename,
            'url': f'/api/upload/{new_filename}',
            'size': os.path.getsize(filepath),
        })

    return success_response(uploaded, '上传成功')


@upload_bp.route('/<filename>', methods=['GET'])
@login_required
def download_file(filename):
    """下载/预览文件"""
    filename = secure_filename(filename)
    upload_dir = current_app.config.get('UPLOAD_FOLDER', 'uploads')

    # Support cross-platform path
    filepath = os.path.join(upload_dir, filename)
    if not os.path.exists(filepath):
        # Also check without secure_filename mangling
        filepath = os.path.join(upload_dir, os.path.basename(filename))
        if not os.path.exists(filepath):
            return error_response('文件不存在', 404)

    return send_file(filepath)


@upload_bp.route('/<filename>', methods=['DELETE'])
@login_required
def delete_file(filename):
    """删除文件"""
    filename = secure_filename(filename)
    upload_dir = current_app.config.get('UPLOAD_FOLDER', 'uploads')
    filepath = os.path.join(upload_dir, filename)

    if not os.path.exists(filepath):
        filepath = os.path.join(upload_dir, os.path.basename(filename))
        if not os.path.exists(filepath):
            return error_response('文件不存在', 404)

    try:
        os.remove(filepath)
    except OSError as e:
        return error_response(f'删除文件失败: {str(e)}', 500)

    return success_response(message='删除文件成功')

